:root {
  /* ================= 自定义保留变量：文字发光阴影 ================= */
  /* 这一层阴影是悬浮白字清晰可见的核心灵魂 */
  --ins-safe-text-shadow: 0 1px 2px #000000, 0 0 5px #000000, 0 0 12px #000000, 0 0 20px rgba(0,0,0,0.9);

  /* ================= 顶部导航栏 ================= */
  --chat-header-bg: transparent;
  --chat-header-blur: 0px;
  --chat-header-border: transparent;
  --chat-header-height: 56px;
  --chat-header-title-color: #ffffff;
  --chat-header-title-size: 17px;
  --chat-header-title-weight: bold;
  --chat-header-subtitle-color: #8e8e8e;
  --chat-header-subtitle-size: 12px;
  --chat-header-icon-color: #ffffff;
  --chat-header-avatar-size: 32px;
  --chat-header-avatar-border: none;
  --chat-header-avatar-radius: 50%;
  --chat-header-avatar-shadow: none;
  --header-btn-gap: 18px;

  /* ================= 消息区域基础 ================= */
  --chat-messages-padding: 12px 16px;
  --chat-messages-gap: 2px;
  --chat-message-max-width: 80%;

  /* ================= 我方气泡（完全透明，纯白悬浮字） ================= */
  --bubble-me-bg: transparent !important;
  --bubble-me-color: #ffffff !important;
  --bubble-me-font-size: 15px;
  --bubble-me-line-height: 1.4;
  --bubble-me-padding: 10px 14px;
  --bubble-me-radius: 0px; /* 透明状态下圆角无意义 */
  --bubble-me-shadow: none !important;
  --bubble-me-border: none !important;
  --bubble-me-link-color: #ffffff;
  --bubble-me-text-shadow: var(--ins-safe-text-shadow) !important;
  --bubble-me-backdrop: none !important;

  /* ================= 对方气泡（完全透明，纯白悬浮字） ================= */
  --bubble-them-bg: transparent !important;
  --bubble-them-color: #ffffff !important;
  --bubble-them-font-size: 15px;
  --bubble-them-line-height: 1.4;
  --bubble-them-padding: 10px 14px;
  --bubble-them-radius: 0px;
  --bubble-them-shadow: none !important;
  --bubble-them-border: none !important;
  --bubble-them-link-color: #ffffff;
  --bubble-them-text-shadow: var(--ins-safe-text-shadow) !important;
  --bubble-them-backdrop: none !important;

  /* ================= 头像设置 ================= */
  --avatar-size: 40px;
  --avatar-radius: 50%;
  --avatar-border: none;
  --avatar-margin: 8px;
  --avatar-shadow: none;

  /* ================= 引用与回复区块 ================= */
  --quote-border-color: rgba(255, 255, 255, 0.45);
  --quote-text-color: #ffffff;
  --reply-block-bg: rgba(25, 30, 35, 0.65);
  --reply-block-name-color: #ffffff;
  --reply-block-text-color: #ffffff;
  --reply-block-radius: 12px;
  --reply-block-padding: 8px 10px;
  --reply-block-border: 1px solid rgba(255, 255, 255, 0.15);
  --reply-block-border-left: none;

  /* ================= 旁白与系统消息 ================= */
  --narration-color: #ffffff;
  --narration-size: 0.87em;
  --narration-bg: transparent;
  --narration-text-shadow: var(--ins-safe-text-shadow);

  --system-msg-bg: transparent;
  --system-msg-color: #ffffff;

  /* 时间戳 */
  --timestamp-color: #ffffff;
  --timestamp-size: 12px;
  --timestamp-weight: bold;
  --timestamp-margin: 4px 0 12px;

  /* 气泡旁状态 & WTS 气泡内时间戳 */
  --status-color: #ffffff;
  --status-size: 10px;
  --status-weight: 400;
  --wa-me-meta-color: #ffffff;
  --wa-me-meta-size: 10px;
  --wa-them-meta-color: #ffffff;
  --wa-them-meta-size: 10px;

  /* ================= 输入区域 ================= */
  --input-area-bg: transparent;
  --input-area-bg-image: none;
  --input-area-border-top: none;
  --input-area-padding: 12px 16px;
  --input-area-min-height: 56px;

  /* 输入框本体 */
  --input-box-bg: transparent;
  --input-box-color: #ffffff;
  --input-box-placeholder: rgba(255, 255, 255, 0.6);
  --input-box-radius: 24px;
  --input-box-padding: 10px 18px;
  --input-box-font-size: 16px;
  --input-box-border: 1px solid rgba(255, 255, 255, 0.2);
  --input-box-blur: none;
  --input-box-shadow: none;
  --input-caret-color: #ffffff;

  /* 回复预览栏 */
  --reply-bar-accent: #ffffff;
  --reply-bar-text-color: #ffffff;

  /* ================= 按钮颜色 ================= */
  --send-btn-bg: transparent;
  --send-btn-bg-hover: transparent;
  --send-btn-color: #ffffff;
  --send-btn-radius: 20px;
  --send-btn-shadow: none;
  --plus-btn-bg: transparent;
  --plus-btn-color: #ffffff;
  --plus-btn-size: 24px;
  --input-btn-color: #ffffff;
}

/* =========================================================
   补充的独立 CSS 规则（处理毛玻璃、高级发光与图标滤镜）
   ========================================================= */

/* 顶栏文字、时间戳、系统消息、输入框文字的深度发光阴影 */
#wechat-chat-detail .chat-header-detail .header-center,
#wechat-chat-detail .chat-header-detail .header-left,
#wechat-chat-detail .chat-header-detail .header-right,
#wechat-chat-detail .chat-time-center span,
#wechat-chat-detail .system-msg span,
#wechat-chat-detail .recall-msg span,
#wechat-chat-detail .bubble-status-time span,
#wechat-chat-detail .chat-input-bar input,
#wechat-chat-detail .chat-input-bar input::placeholder,
#wechat-chat-detail #voice-input-container span,
#wechat-chat-detail .send-btn {
    text-shadow: var(--ins-safe-text-shadow) !important;
}

/* 引用消息块与输入框预览条的高级毛玻璃质感 */
#wechat-chat-detail .quote-block,
#wechat-chat-detail #quote-preview {
    backdrop-filter: blur(16px) saturate(120%) !important;
    -webkit-backdrop-filter: blur(16px) saturate(120%) !important;
    text-shadow: 0 1px 2px rgba(0, 0, 0, 0.6) !important;
}

/* 输入框预览条额外去左边框，保持圆润 */
#wechat-chat-detail #quote-preview {
    background: rgba(25, 30, 35, 0.65) !important;
    border-left: none !important;
    border-radius: 12px !important;
}

/* 语音输入按住说话按钮字体加粗，提升可读性 */
#wechat-chat-detail .chat-input-bar input,
#wechat-chat-detail #voice-input-container span {
    font-weight: 500 !important;
}

/* 底栏各类图片图标的纯白反转与立体阴影滤镜 */
#wechat-chat-detail .chat-input-bar .custom-icon {
    filter: brightness(0) invert(1) drop-shadow(0 1px 3px rgba(0,0,0,0.8)) !important; 
}

/* 发送按钮的半透明细边框，增加精致感 */
#wechat-chat-detail .send-btn {
    border: 1px solid rgba(255, 255, 255, 0.25) !important;
}

